package pe.edu.utp.tmo.controller; import java.security.Principal; import java.time.LocalDateTime; import org.springframework.format.annotation.DateTimeFormat; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import pe.edu.utp.tmo.dto.response.DashboardResponse; import pe.edu.utp.tmo.service.DashboardService; @RestController @RequestMapping("/api/dashboard") public class DashboardController{ private final DashboardService s; public DashboardController(DashboardService s){this.s=s;} @GetMapping("/tmo") ResponseEntity<DashboardResponse> tmo(@RequestParam @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) LocalDateTime inicio,@RequestParam @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) LocalDateTime fin,Principal p){return ResponseEntity.ok(s.resumen(p.getName(),inicio,fin));}}